package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.net.URL;
import java.nio.charset.Charset;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private URL mockUrl;
    private InputStream mockInputStream;

    @BeforeEach
    void setUp() throws IOException {
        mockUrl = mock(URL.class);
        mockInputStream = mock(InputStream.class);
        when(mockUrl.openStream()).thenReturn(mockInputStream);
    }

    @Test
    void parse_WithValidArguments_ShouldReturnCSVParserInstance() throws IOException {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            // no exception from notNull checks
            assertionsMockedStatic.when(() -> Assertions.notNull(mockUrl, "url")).then(invocation -> null);
            assertionsMockedStatic.when(() -> Assertions.notNull(charset, "charset")).then(invocation -> null);
            assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

            CSVParser parser = CSVParser.parse(mockUrl, charset, format);

            assertNotNull(parser);
            assertEquals(format, parser.format);
            assertFalse(parser.isClosed());
        }
        verify(mockUrl).openStream();
        verifyNoMoreInteractions(mockUrl);
    }

    @Test
    void parse_WithNullUrl_ShouldThrowException() {
        Charset charset = Charset.forName("UTF-8");
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "url"))
                    .thenThrow(new IllegalArgumentException("url must not be null"));
            IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class,
                    () -> CSVParser.parse(null, charset, format));
            assertEquals("url must not be null", thrown.getMessage());
        }
    }

    @Test
    void parse_WithNullCharset_ShouldUseUTF8Charset() throws IOException {
        CSVFormat format = mock(CSVFormat.class);

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class);
             MockedStatic<Charset> charsetStatic = Mockito.mockStatic(Charset.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(mockUrl, "url")).then(invocation -> null);
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "charset")).then(invocation -> null);
            assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

            Charset utf8 = Charset.forName("UTF-8");
            charsetStatic.when(() -> Charset.forName("UTF-8")).thenReturn(utf8);

            CSVParser parser = CSVParser.parse(mockUrl, null, format);

            assertNotNull(parser);
            assertEquals(format, parser.format);
        }
        verify(mockUrl).openStream();
    }

    @Test
    void parse_WithNullFormat_ShouldThrowException() {
        Charset charset = Charset.forName("UTF-8");

        try (MockedStatic<Assertions> assertionsMockedStatic = Mockito.mockStatic(Assertions.class)) {
            assertionsMockedStatic.when(() -> Assertions.notNull(mockUrl, "url")).then(invocation -> null);
            assertionsMockedStatic.when(() -> Assertions.notNull(charset, "charset")).then(invocation -> null);
            assertionsMockedStatic.when(() -> Assertions.notNull(null, "format"))
                    .thenThrow(new IllegalArgumentException("format must not be null"));
            IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class,
                    () -> CSVParser.parse(mockUrl, charset, null));
            assertEquals("format must not be null", thrown.getMessage());
        }
    }
}
